105→{% macro content(page) %}
106→<main>
107→    <article>
108→        <div class="title">
109→            {#<h1 class="title">{{ page.title }}</h1>#}
110→            {{ post_macros::page_header(title=page.title) }}
111→
112→                <div class="meta">
113→                    {% if page.date %}
114→                        Posted on <time>{{ page.date | date(format="%Y-%m-%d") }}</time>
115→                    {% endif %}
116→
117→                    {% if page.updated %}
118→                        :: Updated on <time>{{ page.updated | date(format="%Y-%m-%d") }}</time>
119→                    {% endif %}
120→
121→                    {% if page.extra.read_time %}
122→                        :: <time>{{ page.reading_time }}</time> Min Read
123→                    {% endif %}
124→
125→                    {# Inline display of tags directly after the date #}
126→                    {% if page.taxonomies and page.taxonomies.tags %}
127→                            <span class="tags-label"> :: Tags:</span>
128→                            <span class="tags">
129→                                {%- for tag in page.taxonomies.tags %}
130→                                    <a href="{{ get_taxonomy_url(kind='tags', name=tag) }}" class="post-tag">{{ tag }}</a>{% if not loop.last %}, {% endif %}
131→                                {% endfor %}
132→                            </span>
133→                    {% endif %}
134→
135→                    {# View the page on GitHub #}
136→                    {% if page.extra.repo_view | default(value=false) %}
137→                        {# Use the page's repo_url if defined, otherwise use the global edit_repo_url #}
138→                        {% if page.extra.repo_url is defined %}
139→                            {% set repo_url = page.extra.repo_url %}
140→                        {% elif config.extra.repo_url is defined %}
141→                            {% set repo_url = config.extra.repo_url %}
142→                        {% else %}
143→                            {% set repo_url = false %}
144→                        {% endif %}
145→
146→                        {% if repo_url %}
147→                            {% set final_url = repo_url ~ page.relative_path %}
148→                            :: <a href="{{ final_url }}" target="_blank" rel="noopener noreferrer"> Source Code</a>
149→                        {% endif %}
150→                    {% endif %}
151→
152→                    {% if page.draft %}
153→                        <span class="draft-label">DRAFT</span>
154→                    {% endif %}
155→
156→                </div>
157→        </div>
158→
159→        {% if page.extra.tldr %}
160→            <div class="tldr">
161→                <strong>tl;dr:</strong>
162→                {{ page.extra.tldr }}
163→            </div>
164→        {% endif %}
165→
166→        {# Optional table of contents #}
167→        {% if config.extra.toc | default(value=false) %}
168→        {% if page.toc %}
169→            <div class="toc-container">
170→                <h1 class="toc-title">Table of Contents</h1>
171→                <ul class="toc-list">
172→                    {% for h1 in page.toc %}
173→                        <li>
174→                            <a href="{{ h1.permalink | safe }}">{{ h1.title }}</a>
175→                            {% if h1.children %}
176→                                <ul>
177→                                    {% for h2 in h1.children %}
178→                                        <li>
179→                                            <a href="{{ h2.permalink | safe }}">{{ h2.title }}</a>
180→                                        </li>
181→
182→                                        {% if h2.children %}
183→                                            <ul>
184→                                                {% for h3 in h2.children %}
185→                                                    <li>
186→                                                        <a href="{{ h3.permalink | safe }}">{{ h3.title }}</a>
187→                                                    </li>
188→                                                {% endfor %}
189→                                            </ul>
190→                                        {% endif %}
191→                                    {% endfor %}
192→                                </ul>
193→                            {% endif %}
194→                        </li>
195→                    {% endfor %}
196→                </ul>
197→            </div>
198→        {% endif %}
199→        {% endif %}
200→
201→        <section class="body">
202→            {{ page.content | safe }}
203→        </section>
204→
205→        <div class="share-links">
206→            <span>Share:</span>
207→            <a href="https://twitter.com/intent/tweet?url={{ page.permalink | urlencode }}&text={{ page.title | urlencode }}" target="_blank" rel="noopener">
208→                <img alt="Twitter/X" src="{{ get_url(path='social_icons/x-twitter.svg') }}"> Twitter/X
209→            </a>
210→            <a href="https://www.linkedin.com/sharing/share-offsite/?url={{ page.permalink | urlencode }}" target="_blank" rel="noopener">
211→                <img alt="LinkedIn" src="{{ get_url(path='social_icons/linkedin.svg') }}"> LinkedIn
212→            </a>
213→            <a href="https://reddit.com/submit?url={{ page.permalink | urlencode }}&title={{ page.title | urlencode }}" target="_blank" rel="noopener">
214→                <img alt="Reddit" src="{{ get_url(path='social_icons/reddit.svg') }}"> Reddit
215→            </a>
216→            <a href="https://news.ycombinator.com/submitlink?u={{ page.permalink | urlencode }}&t={{ page.title | urlencode }}" target="_blank" rel="noopener">
217→                <img alt="Hacker News" src="{{ get_url(path='social_icons/hacker-news.svg') }}"> Hacker News
218→            </a>
219→            <a href="mailto:?subject={{ page.title | urlencode }}&body={{ page.permalink | urlencode }}" rel="noopener">
220→                <img alt="Email" src="{{ get_url(path='social_icons/email.svg') }}"> Email
221→            </a>
222→        </div>
223→
224→        <div class="comments-container">
225→            <script src="https://utteranc.es/client.js"
226→                repo="kennetheversole/eversole.dev"
227→                issue-term="pathname"
228→                theme="preferred-color-scheme"
229→                crossorigin="anonymous"
230→                async>
231→            </script>
232→        </div>
233→    </article>
234→</main>
