:root {
  /* Used for: block comment, hr, ... */
  --border-color: var(--border-color);

  /* Fonts */
  --text-font: 'Josefin Sans';
  --header-font: 'Josefin Sans';
  --code-font: 'JetBrains Mono', monospace;
}


.site-footer {
    color: white;
    text-align: center;
}

.footer-content {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 2rem;
}

.socials {
    display: flex;
    gap: 1rem;
    justify-content: center;
}

.copyright {
    text-align: center;
    padding-top: 1rem;
}
.logoimage{
    width: 75px;
    border: none;
    pointer-events: none;
}
html {
  background-color: var(--bg-0);
  color: var(--text-0);
  font-family: var(--text-font);
  line-height: 1.6em;
}

.content {
  max-width: 1000px;
  margin: 0 auto;
  padding: 0 24px;
  word-wrap: break-word;
}

@media all and (min-width:640px) {
  html {
    font-size: 18px;
  }
}

@media all and (min-width:720px) {
  html {
    font-size: 18px;
  }
}

@media all and (min-width:960px) {
  html {
    font-size: 18px;
  }
}

.reading-progress {
  position: fixed;
  top: 0;
  left: 0;
  width: 0;
  height: 3px;
  background-color: var(--primary-color);
  z-index: 9999;
  transition: width 0.1s linear;
}

.share-links {
  margin-top: 2rem;
  padding-top: 1.5rem;
  border-top: 3px solid var(--border-color);
  display: flex;
  align-items: center;
  gap: 1rem;
  flex-wrap: wrap;

  span {
    color: var(--text-1);
    font-weight: bold;
  }

  a {
    border-bottom: none;
    padding: 0.3rem 0.8rem;
    border-radius: 4px;
    background-color: var(--bg-1);
    color: var(--text-0);
    font-size: 0.9rem;
    transition: background-color 0.2s;
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;

    img {
      width: 16px;
      height: 16px;
      border: none;
    }

    &:hover {
      background-color: var(--primary-color);
      color: var(--hover-color);

      img {
        filter: brightness(0) invert(1);
      }
    }
  }
}

.comments-container {
  margin-top: 2rem;
  padding-top: 1.5rem;
  border-top: 3px solid var(--border-color);
}

